#include<cstdio>
#include<vector>
#include<cmath>
#include<set>
#include<string>
using namespace std;typedef pair<int,int>P;int W,H,cx,cy,px,py,sc;bool ref;vector<P>C;struct Hist{int px,py,cx,cy;char h[9];};vector<Hist>hist;vector<P>filt(vector<P>&c,int px,int py,int cx,int cy,const char*h,int s){vector<P>r;for(auto[bx,by]:c){long long dp=(long long)(bx-px)*(bx-px)+(long long)(by-py)*(by-py);long long dc=(long long)(bx-cx)*(bx-cx)+(long long)(by-cy)*(by-cy);if(h[0]=='W'&&dc<dp)r.push_back({bx,by});else if(h[0]=='C'&&dc>dp)r.push_back({bx,by});else if(h[0]=='S'&&(s>1||dc==dp))r.push_back({bx,by});}return r;}int main(){int N;scanf("%d%d%d%d%d",&W,&H,&N,&cx,&cy);sc=1;while((long long)((W+sc-1)/sc)*((H+sc-1)/sc)>62500)sc*=2;for(int y=0;y<H;y+=sc)for(int x=0;x<W;x+=sc)C.push_back({min(x+sc/2,W-1),min(y+sc/2,H-1)});px=cx;py=cy;ref=sc==1;for(;;){char h[9];scanf("%s",h);if(h[0]=='W'||h[0]=='C'||h[0]=='S'){hist.push_back({px,py,cx,cy});sprintf(hist.back().h,"%s",h);C=filt(C,px,py,cx,cy,h,sc);if(!ref&&C.size()<=3){set<long long>s;vector<P>exp;for(auto[sx,sy]:C)for(int ny=sy-sc;ny<=sy+sc;ny++)for(int nx=sx-sc;nx<=sx+sc;nx++){int px2=max(0,min(W-1,nx)),py2=max(0,min(H-1,ny));long long k=(long long)py2*W+px2;if(!s.count(k)){s.insert(k);exp.push_back({px2,py2});}}for(auto&hh:hist)exp=filt(exp,hh.px,hh.py,hh.cx,hh.cy,hh.h,1);C=exp;sc=1;ref=1;}}px=cx;py=cy;if(C.size()<=1){if(C.size()){cx=C[0].first;cy=C[0].second;}}else if(C.size()<=80){int best=1e9,bx=cx,by=cy;for(auto[tx,ty]:C){if(tx==cx&&ty==cy)continue;int w=0,c2=0;for(auto[ax,ay]:C){long long dp=(long long)(ax-cx)*(ax-cx)+(long long)(ay-cy)*(ay-cy);long long dt=(long long)(ax-tx)*(ax-tx)+(long long)(ay-ty)*(ay-ty);if(dt<dp)w++;else if(dt>dp)c2++;}int s=abs(w-c2);if(s<best){best=s;bx=tx;by=ty;}}cx=bx;cy=by;}else{long long sx=0,sy=0;for(auto[x,y]:C){sx+=x;sy+=y;}cx=round((double)sx/C.size());cy=round((double)sy/C.size());}if(cx==px&&cy==py&&C.size()){long long md=-1;for(auto[x,y]:C){long long d=(long long)(x-cx)*(x-cx)+(long long)(y-cy)*(y-cy);if(d>md){md=d;cx=x;cy=y;}}}printf("%d %d\n",cx,cy);fflush(stdout);}}